import org.junit.jupiter.api.Test;

class ScalarEvaluationEffectsTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void nativeAndRegisteredCoreFunctionsAreRepeatable() {
		ValueConstant expected = new ValueConstant(SimpleValueFactory.getInstance().createLiteral("expected"));

		assertEquals(REPEATABLE,
				ScalarEvaluationEffects.effectOf(new Compare(new Var("value"), expected, Compare.CompareOp.EQ)));
		assertEquals(REPEATABLE, ScalarEvaluationEffects.effectOf(new FunctionCall(FN.CONTAINS.stringValue(),
				new Str(new Var("value")), expected.clone())));
	}

	@Test
	void standardCompositeOperatorsRemainRepeatable() {
		ValueConstant expected = new ValueConstant(VF.createLiteral("expected"));
		And condition = new And(
				new Compare(new Var("value"), expected, Compare.CompareOp.EQ),
				new Bound(new Var("value")));

		assertEquals(REPEATABLE, ScalarEvaluationEffects.effectOf(condition));
		StatementPattern subquery = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		assertEquals(REPEATABLE, ScalarEvaluationEffects.effectOf(new Exists(subquery)));
		assertEquals(VOLATILE,
				ScalarEvaluationEffects.effectOf(new Exists(new Filter(subquery.clone(), new FunctionCall("RAND")))));
	}

	@Test
	void existsFailsClosedAtExternalAndUnknownTupleBoundaries() {
		StatementPattern subquery = new StatementPattern(new Var("s"), new Var("p"), new Var("o"));
		Service service = new Service(Var.of("endpoint", VF.createIRI("urn:test:service")), subquery.clone(),
				"?s ?p ?o .", Map.of(), null, false);
		TupleFunctionCall tupleFunction = new TupleFunctionCall();
		tupleFunction.setURI("urn:test:tuple-function");
		tupleFunction.addResultVar(new Var("result"));

		assertEquals(REPEATABLE, ScalarEvaluationEffects.effectOf(new Exists(subquery.clone())));
		assertEquals(UNKNOWN, ScalarEvaluationEffects.effectOf(new Exists(service)));
		assertEquals(UNKNOWN, ScalarEvaluationEffects.effectOf(new Exists(tupleFunction)));
		assertEquals(UNKNOWN,
				ScalarEvaluationEffects.effectOf(new Exists(new ForeignUnaryTupleExpr(subquery.clone()))));
	}

	@Test
	void queryStableAndVolatileBuiltInsKeepTheirDistinctEffects() {
		assertEquals(QUERY_STABLE, ScalarEvaluationEffects.effectOf(new FunctionCall("NOW")));
		assertEquals(VOLATILE, ScalarEvaluationEffects.effectOf(new FunctionCall("RAND")));
		assertEquals(VOLATILE, ScalarEvaluationEffects.effectOf(new FunctionCall("UUID")));
		assertEquals(VOLATILE, ScalarEvaluationEffects.effectOf(new FunctionCall("STRUUID")));
		assertEquals(VOLATILE, ScalarEvaluationEffects.effectOf(new BNodeGenerator()));
	}

	@Test
	void customFunctionRequiresQueryConstantArguments() {
		Function function = new DefaultFalseFunction("urn:test:default-false");
		FunctionRegistry.getInstance().add(function);
		try {
			assertEquals(QUERY_STABLE, ScalarEvaluationEffects.effectOf(
					new FunctionCall(function.getURI(), new ValueConstant(VF.createLiteral("constant")))));
			assertEquals(UNKNOWN,
					ScalarEvaluationEffects.effectOf(new FunctionCall(function.getURI(), new Var("rowValue"))));
		} finally {
			FunctionRegistry.getInstance().remove(function);
		}
	}

	@Test
	void missingDynamicAndForeignExpressionsFailClosed() {
		assertEquals(UNKNOWN, ScalarEvaluationEffects.effectOf(new FunctionCall("urn:test:missing")));
		assertEquals(UNKNOWN, ScalarEvaluationEffects.effectOf(
				new FunctionCall("http://spinrdf.org/spif#invoke", new Var("function"))));
		assertEquals(UNKNOWN, ScalarEvaluationEffects.effectOf(new ForeignUnaryValueExpr(new Var("value"))));
	}

	@Test
	void nativeStringConversionIsRepeatable() {
		assertEquals(REPEATABLE, ScalarEvaluationEffects.effectOf(new Str(new Var("value"))));
	}

	private static final class DefaultFalseFunction implements Function {
		private final String uri;

		private DefaultFalseFunction(String uri) {
			this.uri = uri;
		}

		@Override
		public String getURI() {
			return uri;
		}

		@Override
		public Value evaluate(ValueFactory valueFactory, Value... args) throws ValueExprEvaluationException {
			return args.length == 0 ? valueFactory.createLiteral("constant") : args[0];
		}
	}

	private static final class ForeignUnaryValueExpr extends UnaryValueOperator {
		private ForeignUnaryValueExpr(ValueExpr arg) {
			super(arg);
		}

		@Override
		public <X extends Exception> void visit(QueryModelVisitor<X> visitor) throws X {
			visitor.meetOther(this);
		}
	}

	private static final class ForeignUnaryTupleExpr extends UnaryTupleOperator {
		private ForeignUnaryTupleExpr(StatementPattern arg) {
			super(arg);
		}

		@Override
		public <X extends Exception> void visit(QueryModelVisitor<X> visitor) throws X {
			visitor.meetOther(this);
		}
	}
}
